/**
 * Main router goes to home page 
 * and other pages can be called from the home page
 */
import React from "react";
import './index.css';
import { Routes, Route } from 'react-router-dom'

import Home from './pages/Home';
import Gallery from './pages/Gallery'
import PageNotFound from './pages/PageNotFound';
import VideoGames from './pages/VideoGames';
import ContactThanks from './pages/ContactThanks';
 
import LinksTest from "./LinksTest";

 function App() {

  return (
    <div className="App ">
      {/* <LinksTest/> */}
      <div className="py-10 text-xl font-bold text-center">

            <Routes>
          <Route path="/" element={
            <>
            Home and Nav bar
              <LinksTest/>
            </>
          
          }></Route>
          <Route path="/about" element={<h1>About</h1>}></Route>
          <Route path="/project" element={<h1>Projects</h1>}></Route>
          <Route path="/contact" element={<h1>Contact</h1>}></Route>
        </Routes>
      </div>
    </div>
        );





   return (
     <div className='body-font font-poppins'>
         <Routes>
           <Route path="/" element={<Home/>}/>
           <Route path="Gallery" element={<Gallery/>}/>
           <Route path="VideoGames" element={<VideoGames/>}/>
           <Route path="Contact" element={<ContactThanks/>}/>
           <Route path="*" element={<PageNotFound/>} /> 
         </Routes>
     </div>
   );
 }
 
 export default App;
 